var ORCHESTRATOR_ID = 'NKSnUIomh70jdb7g';
var WATCHDOG_ID = 'FD0OCHSatdMzYc2I';
var cutoffMs = Date.now() - (60 * 60 * 1000);

var apiResponse = $input.first().json;
var allExecutions = (apiResponse && Array.isArray(apiResponse.data)) ? apiResponse.data : [];

var executions = [];
allExecutions.forEach(function(e) {
  var isIgnored = (e.workflowId === ORCHESTRATOR_ID || e.workflowId === WATCHDOG_ID);
  var execMs = e.startedAt ? new Date(e.startedAt).getTime() : cutoffMs;
  var isRecent = execMs >= cutoffMs;
  if (!isIgnored && isRecent) {
    executions.push(e);
  }
});

var grouped = {};
executions.forEach(function(exec) {
  var wfId = exec.workflowId || 'unknown';
  var wfName = (exec.workflowData && exec.workflowData.name) ? exec.workflowData.name : wfId;
  if (!grouped[wfId]) {
    grouped[wfId] = { name: wfName, count: 0, lastTime: '' };
  }
  grouped[wfId].count = grouped[wfId].count + 1;
  if (!grouped[wfId].lastTime || exec.startedAt > grouped[wfId].lastTime) {
    grouped[wfId].lastTime = exec.startedAt;
  }
});

var lines = [];
Object.values(grouped).forEach(function(w) {
  var lastTime = w.lastTime ? new Date(w.lastTime).toLocaleString('pt-BR') : 'desconhecido';
  lines.push('ERRO: ' + w.name + ' - ' + w.count + ' vez(es) | Ultimo: ' + lastTime);
});

var total = executions.length;
var unique = Object.keys(grouped).length;
var now = new Date().toLocaleString('pt-BR');
var reportText = '';

if (total > 0) {
  reportText = 'WATCHDOG REPORT - ' + now + '\n\n' + total + ' erro(s) na ultima hora em ' + unique + ' workflow(s):\n\n' + lines.join('\n') + '\n\nSelf-Healing Orchestrator acionado automaticamente.';
} else {
  reportText = 'WATCHDOG OK - ' + now + ' - Sem erros na ultima hora.';
}

return [{
  json: {
    hasErrors: total > 0,
    reportText: reportText,
    total: total,
    unique: unique
  }
}];
